void worker() {
    std::lock_guard<std::mutex> lk(m);
    ready = true;
    std::notify_all_at_thread_exit(cv, std::move(lk));
}
int main() {
    std::thread t(worker);
    std::unique_lock<std::mutex> lk(m);
    cv.wait(lk, []{ return ready; });
    t.join();
    std::cout << "done";
}

